theorem P2026AIMEI_9 :
    let RollSeq := Fin 6 → Fin 6
    let StickerVisible : RollSeq → Fin 6 → Prop :=
      fun σ k => ∀ j : Fin 6, k < j → σ j ≠ σ k
    let ExactlyOneBlankFace : RollSeq → Prop :=
      fun σ => ((Finset.univ : Finset (Fin 6)).image σ).card = 5
    let EvenStickersVisible : RollSeq → Prop :=
      fun σ =>
        StickerVisible σ ⟨1, by decide⟩ ∧
          StickerVisible σ ⟨3, by decide⟩ ∧ StickerVisible σ ⟨5, by decide⟩
    let totalEvenVisible : ℕ :=
      ((Finset.univ : Finset RollSeq).filter fun σ => EvenStickersVisible σ).card
    let favorableEvenVisibleWithOneBlank : ℕ :=
      ((Finset.univ : Finset RollSeq).filter fun σ =>
        EvenStickersVisible σ ∧ ExactlyOneBlankFace σ).card
    let p : ℚ := (favorableEvenVisibleWithOneBlank : ℚ) / (totalEvenVisible : ℚ)
    IsLeast
      {s : ℕ |
        ∃ m n : ℕ,
          Nat.Coprime m n ∧ p = (m : ℚ) / (n : ℚ) ∧ s = m + n}
      P2026AIMEI_9_answer := by sorry

