theorem P2026AIMEII_3 :
    ((Finset.range 2026).filter fun n : ℕ =>
      ∃ C D : ℝ × ℝ,
        let A : ℝ × ℝ := (0, 0);
        let B : ℝ × ℝ := ((n : ℝ), 0);
        let E : ℝ × ℝ := (0, 20);
        let dist : ℝ × ℝ → ℝ × ℝ → ℝ :=
          fun P Q =>
            Real.sqrt ((P.1 - Q.1) ^ (2 : ℕ) + (P.2 - Q.2) ^ (2 : ℕ));
        let dotAt : ℝ × ℝ → ℝ × ℝ → ℝ × ℝ → ℝ :=
          fun P Q R => (P.1 - Q.1) * (R.1 - Q.1) + (P.2 - Q.2) * (R.2 - Q.2);
        let crossAt : ℝ × ℝ → ℝ × ℝ → ℝ × ℝ → ℝ :=
          fun P Q R => (Q.1 - P.1) * (R.2 - Q.2) - (Q.2 - P.2) * (R.1 - Q.1);
        let twiceArea : ℝ :=
          A.1 * B.2 - A.2 * B.1 +
          (B.1 * C.2 - B.2 * C.1) +
          (C.1 * D.2 - C.2 * D.1) +
          (D.1 * E.2 - D.2 * E.1) +
          (E.1 * A.2 - E.2 * A.1);
        0 < (n : ℝ) ∧
        0 < C.1 ∧
        0 < D.1 ∧
        dist A B = (n : ℝ) ∧
        dist A E = 20 ∧
        dist B C = 14 * Real.sqrt 2 ∧
        dist D E < dist A B ∧
        dotAt B A E = 0 ∧
        dotAt D E A = 0 ∧
        dotAt A B C = dist A B * dist B C * Real.sqrt 2 / 2 ∧
        dotAt C D E = dist C D * dist D E * Real.sqrt 2 / 2 ∧
        0 < crossAt A B C ∧
        crossAt B C D < 0 ∧
        0 < crossAt C D E ∧
        0 < crossAt D E A ∧
        0 < crossAt E A B ∧
        (∃ m : ℕ, |twiceArea| / 2 = 16 * (m : ℝ))).card = P2026AIMEII_3_answer := by sorry

