theorem P2026HMMT_11 :
    let Test := Fin 4 → Fin 4
    let hasTopic : Test → Fin 4 → Prop :=
      fun test topic => ∃ q : Fin 4, test q = topic
    let given : Finset Test :=
      (Finset.univ : Finset Test).filter fun test =>
        hasTopic test 0 ∧ hasTopic test 1 ∧ hasTopic test 2
    let favorable : Finset Test :=
      given.filter fun test => hasTopic test 3
    ((favorable.card : ℚ) / (given.card : ℚ)) = P2026HMMT_11_answer := by sorry

