          let onSegment : ℝ × ℝ → ℝ × ℝ → ℝ × ℝ → Prop :=
            fun P Q S =>
              ∃ t : ℝ,
                0 ≤ t ∧ t ≤ 1 ∧
                S.1 = (1 - t) * P.1 + t * Q.1 ∧
                S.2 = (1 - t) * P.2 + t * Q.2;
          let tangentToSegment : ℝ × ℝ → ℝ → ℝ × ℝ → ℝ × ℝ → Prop :=
            fun O ρ P Q =>
              P ≠ Q ∧
              ∃ T : ℝ × ℝ,
                onSegment P Q T ∧ dist O T = ρ ∧ dotAt P T O = 0;
          let sameSideOfLine : ℝ × ℝ → ℝ × ℝ → ℝ × ℝ → ℝ × ℝ → Prop :=
            fun P Q S T => 0 < crossAt P Q S * crossAt P Q T;
          let inradius : ℝ :=
            |crossAt A B C| / (dist A B + dist B C + dist C A);
          A ≠ B ∧ A ≠ C ∧ B ≠ C ∧
          0 < R ∧
          dist O1 A = R ∧ dist O1 B = R ∧ dist O1 C = R ∧
          dotAt B A C > 0 ∧ dotAt A B C > 0 ∧ dotAt A C B > 0 ∧
          onSegment B C D ∧
